1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const COMPONENT_TYPES = ["rune", "moonstone"];
12	const COMPONENT_PREMIUM = 25;
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: Item): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	const isMainItem = (item: Item): boolean => !isComponent(item);
20	
21	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
22	// BLOCK_PREMIUM; any other count is priced per component.
23	const componentGroupBasePremium = (count: number): number =>
24	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
25	
26	interface Item {
27	  type: string;
28	}
29	
30	interface QuoteStep {
31	  items: Item[];
32	}
33	
34	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
35	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
36	// that is only spuriously above a whole number.
37	const roundUpInMHPCOsFavor = (amount: number): number =>
38	  Math.ceil(Number(amount.toFixed(6)));
39	
40	const basePremiumForItem = (item: Item): number =>
41	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
42	
43	// Each main item is priced on its own.
44	const mainItemsBasePremium = (items: Item[]): number =>
45	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
46	
47	const countByType = (items: Item[]): Map<string, number> => {
48	  const counts = new Map<string, number>();
49	  for (const item of items) {
50	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
51	  }
52	  return counts;
53	};
54	
55	// Components are grouped by type, and each group is block-priced.
56	const componentsBasePremium = (components: Item[]): number =>
57	  [...countByType(components).values()].reduce(
58	    (sum, count) => sum + componentGroupBasePremium(count),
59	    0,
60	  );
61	
62	export const quote = (
63	  customer: unknown,
64	  step: QuoteStep,
65	  quoteIndex: number,
66	): number => {
67	  const mainItems = step.items.filter(isMainItem);
68	  const components = step.items.filter(isComponent);
69	
70	  const policyBasePremium =
71	    mainItemsBasePremium(mainItems) + componentsBasePremium(components);
72	  const withFirstInsurance = policyBasePremium * (1 + FIRST_INSURANCE_SURCHARGE);
73	  const total = withFirstInsurance + PROCESSING_FEE;
74	  return roundUpInMHPCOsFavor(total);
75	};
76	
77	export const claim = (...args: unknown[]): unknown => {
78	  return undefined; // Intentionally not implemented
79	};
